class Solution:
    def countGoodIntegers(self, n, k):
        # Independent approach: enumerate every distinct digit multiset directly
        # (stars-and-bars over the 10 digits) instead of generating palindromes
        # from their half, then check per multiset whether some half arrangement
        # of it forms a k-palindromic number.
        from itertools import combinations_with_replacement, permutations
        from math import factorial

        half = n // 2
        odd = n % 2
        total = 0
        for multiset in combinations_with_replacement(range(10), n):
            counts = [0] * 10
            for d in multiset:
                counts[d] += 1
            odd_digits = [d for d in range(10) if counts[d] % 2 == 1]
            if odd == 0 and odd_digits:
                continue
            if odd == 1 and len(odd_digits) != 1:
                continue
            half_pool = []
            middle = None
            for d in range(10):
                half_pool.extend([d] * (counts[d] // 2))
                if counts[d] % 2 == 1:
                    middle = d
            if len(half_pool) != half:
                continue
            found = False
            for perm in set(permutations(half_pool)):
                if half > 0 and perm[0] == 0:
                    continue
                if half == 0:
                    if middle == 0:
                        continue
                    full = str(middle)
                else:
                    half_str = ''.join(map(str, perm))
                    full = half_str + str(middle) + half_str[::-1] if odd else half_str + half_str[::-1]
                if int(full) % k == 0:
                    found = True
                    break
            if not found:
                continue
            denom = 1
            for d in range(10):
                denom *= factorial(counts[d])
            total_perms = factorial(n) // denom
            zero_leading = 0
            if counts[0] > 0:
                zero_leading = factorial(n - 1) // (factorial(counts[0] - 1) * (denom // factorial(counts[0])))
            total += total_perms - zero_leading
        return total

