from math import factorial

class Solution:
    def countGoodIntegers(self, n, k):
        half = (n + 1) // 2
        seen = set()
        total = 0
        start = 10 ** (half - 1) if half > 1 else 0
        end = 10 ** half
        for p in range(start, end):
            ps = str(p)
            if n % 2 == 0:
                full = ps + ps[::-1]
            else:
                full = ps + ps[-2::-1]
            if int(full) % k != 0:
                continue
            key = tuple(sorted(full))
            if key in seen:
                continue
            seen.add(key)
            counts = {}
            for ch in full:
                counts[ch] = counts.get(ch, 0) + 1
            denom = 1
            for c in counts.values():
                denom *= factorial(c)
            total_perms = factorial(n) // denom
            zero_leading = 0
            if '0' in counts:
                zero_leading = factorial(n - 1) // (factorial(counts['0'] - 1) * (denom // factorial(counts['0'])))
            total += total_perms - zero_leading
        return total

