var countGoodIntegers = function(n, k) {
    function factorial(x) { let r = 1; for (let i = 2; i <= x; i++) r *= i; return r; }
    const half = Math.floor((n + 1) / 2);
    const seen = new Set();
    let total = 0;
    const start = half > 1 ? Math.pow(10, half - 1) : 0;
    const end = Math.pow(10, half);
    for (let p = start; p < end; p++) {
        const ps = String(p);
        let full;
        if (n % 2 === 0) full = ps + ps.split('').reverse().join('');
        else full = ps + ps.slice(0, -1).split('').reverse().join('');
        const num = BigInt(full);
        if (num % BigInt(k) !== 0n) continue;
        const key = full.split('').sort().join('');
        if (seen.has(key)) continue;
        seen.add(key);
        const counts = {};
        for (const ch of full) counts[ch] = (counts[ch] || 0) + 1;
        let denom = 1;
        for (const c of Object.values(counts)) denom *= factorial(c);
        const totalPerms = factorial(n) / denom;
        let zeroLeading = 0;
        if (counts['0']) {
            zeroLeading = factorial(n - 1) / (factorial(counts['0'] - 1) * (denom / factorial(counts['0'])));
        }
        total += totalPerms - zeroLeading;
    }
    return total;
};
